#define DHT11_GPIO 7

// Structure to hold temperature and humidity data
typedef struct {
    float temperature;
    float humidity;
    int valid;
} DHT11Data;

// Global variable for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signalHandler(int signum) {
    terminate = 1;
}

// Function to read data from the DHT11 sensor
DHT11Data readDHT11(int gpio) {
    DHT11Data data = {0.0, 0.0, 0};
    int bit_count = 0;
    int byte_index = 0;
    unsigned int data_buffer[5] = {0, 0, 0, 0, 0};

    gpioSetMode(gpio, PI_OUTPUT);
    gpioWrite(gpio, 0);
    gpioDelay(1);
    gpioWrite(gpio, 1);
    gpioDelay(30);

    gpioSetMode(gpio, PI_INPUT);

    // Wait for the DHT11 to pull the line low (start signal)
    int timeout = 0;
    while (gpioRead(gpio) == 1 && timeout < 100) {
        gpioDelay(1); // Small delay to avoid busy-waiting
        timeout++;
    }

    if (timeout >= 100) {
        fprintf(stderr, "Error: DHT11 start signal timeout.\n");
        return data; // Return invalid data
    }

    timeout = 0;
    while (gpioRead(gpio) == 0 && timeout < 100) {
        gpioDelay(1);
        timeout++;
    }

    if (timeout >= 100) {
        fprintf(stderr, "Error: DHT11 data low timeout.\n");
        return data; // Return invalid data
    }

    timeout = 0;
    while (gpioRead(gpio) == 1 && timeout < 100) {
        gpioDelay(1);
        timeout++;
    }

    if (timeout >= 100) {
        fprintf(stderr, "Error: DHT11 data high timeout.\n");
        return data; // Return invalid data
    }

    // Read 40 bits of data
    for (int i = 0; i < 40; i++) {
        timeout = 0;
        while (gpioRead(gpio) == 0 && timeout < 100) {
            gpioDelay(1);
            timeout++;
        }

        if (timeout >= 100) {
            fprintf(stderr, "Error: DHT11 data low timeout at bit %d.\n", i);
            return data; // Return invalid data
        }

        unsigned int t = gpioTick();

        timeout = 0;
        while (gpioRead(gpio) == 1 && timeout < 100) {
            gpioDelay(1);
            timeout++;
        }

        if (timeout >= 100) {
            fprintf(stderr, "Error: DHT11 data high timeout at bit %d.\n", i);
            return data; // Return invalid data
        }

        unsigned int pulse_length = gpioTick() - t;
        if (pulse_length > 40) {
            data_buffer[byte_index] |= (1 << (7 - bit_count));
        }

        bit_count++;
        if (bit_count == 8) {
            bit_count = 0;
            byte_index++;
        }
    }

    // Verify checksum
    if ((data_buffer[0] + data_buffer[1] + data_buffer[2] + data_buffer[3]) & 0xFF != data_buffer[4]) {
        fprintf(stderr, "Error: Checksum failure.\n");
        return data; // Return invalid data
    }

    // Convert data to temperature and humidity
    data.humidity = (float)data_buffer[0];
    data.temperature = (float)data_buffer[2];
    data.valid = 1;

    return data;
}

// Function to display the temperature and humidity data
