    terminate = 1;
    fprintf(stderr, "\nCaught signal %d, terminating gracefully...\n", sig);
}

// Function to read data from the DHT11 sensor
int readDHT11Data(int gpioPin, DHT11Data *data) {
    int i, j, bit_idx, byte_idx;
    uint8_t data_buffer[5] = {0, 0, 0, 0, 0};

    // Set the GPIO pin as output
    gpioSetMode(gpioPin, PI_OUTPUT);

    // Send a start signal (low for >1ms, then high)
    gpioWrite(gpioPin, 0);
    gpioDelay(1);
    gpioWrite(gpioPin, 1);
    gpioDelay(30);

    // Set the GPIO pin as input
    gpioSetMode(gpioPin, PI_INPUT);

    // Wait for the DHT11 to pull the line low (acknowledgement signal)
    int timeout = 0;
    while (gpioRead(gpioPin) == 1 && timeout < 100) {
        gpioDelay(1); // Wait 1 microsecond
        timeout++;
    }
    if (timeout >= 100) {
        fprintf(stderr, "DHT11 acknowledgement timeout\n");
        return -1; // Indicate error
    }

    timeout = 0;
    while (gpioRead(gpioPin) == 0 && timeout < 100) {
        gpioDelay(1);
        timeout++;
    }
    if (timeout >= 100) {
        fprintf(stderr, "DHT11 data timeout (low)\n");
        return -1;
    }

    timeout = 0;
    while (gpioRead(gpioPin) == 1 && timeout < 100) {
        gpioDelay(1);
        timeout++;
    }
    if (timeout >= 100) {
        fprintf(stderr, "DHT11 data timeout (high)\n");
        return -1;
    }

    // Read 40 bits of data (5 bytes)
    for (byte_idx = 0; byte_idx < 5; byte_idx++) {
        data_buffer[byte_idx] = 0;
        for (bit_idx = 0; bit_idx < 8; bit_idx++) {
            timeout = 0;
            while (gpioRead(gpioPin) == 0 && timeout < 100) {
                gpioDelay(1);
                timeout++;
            }
            if (timeout >= 100) {
                fprintf(stderr, "DHT11 data timeout (bit low)\n");
                return -1;
            }

            timeout = 0;
            while (gpioRead(gpioPin) == 1 && timeout < 100) {
                gpioDelay(1);
                timeout++;
            }
            if (timeout >= 100) {
                fprintf(stderr, "DHT11 data timeout (bit high)\n");
                return -1;
            }

            if (gpioRead(gpioPin) == 1) {
                data_buffer[byte_idx] |= (1 << (7 - bit_idx));
            }
        }
    }

    // Verify checksum
    if ((data_buffer[0] + data_buffer[1] + data_buffer[2] + data_buffer[3]) != data_buffer[4]) {
        fprintf(stderr, "DHT11 checksum failure\n");
        return -1; // Indicate error
    }

    // Populate the DHT11Data struct
    data->humidity = (float)data_buffer[0];
    data->temperature = (float)data_buffer[2];

    return 0; // Indicate success
}

// Function to validate temperature and humidity data
int validateData(float temperature, float humidity) {
    if (temperature < -20.0 || temperature > 80.0) {
        fprintf(stderr, "Temperature out of range: %.1f\n", temperature);
        return -1;
    }
    if (humidity < 0.0 || humidity > 100.0) {
        fprintf(stderr, "Humidity out of range: %.1f\n", humidity);
        return -1;
    }
    return 0; // Indicate success
