// Function to read data from the DHT11 sensor
DHT11Data read_dht11(int gpio_pin) {
    DHT11Data data = {0.0, 0.0, 0};
    int i, j;
    unsigned char dht11_data[5] = {0, 0, 0, 0, 0};

    // Set the GPIO pin as output
    gpioSetMode(gpio_pin, PI_OUTPUT);

    // Send start signal (low for 1ms)
    gpioWrite(gpio_pin, 0);
    gpioDelay(1);
    gpioWrite(gpio_pin, 1);
    gpioDelay(30);

    // Set the GPIO pin as input
    gpioSetMode(gpio_pin, PI_INPUT);

    // Wait for response (low then high)
    int timeout = 0;
    while (gpioRead(gpio_pin) == 1) {
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 response on GPIO %d\n", gpio_pin);
            data.error = -1; // Indicate error
            return data;
        }
        gpioDelay(1);
    }

    timeout = 0;
    while (gpioRead(gpio_pin) == 0) {
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 response on GPIO %d\n", gpio_pin);
            data.error = -1; // Indicate error
            return data;
        }
        gpioDelay(1);
    }

    timeout = 0;
    while (gpioRead(gpio_pin) == 1) {
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 response on GPIO %d\n", gpio_pin);
            data.error = -1; // Indicate error
            return data;
        }
        gpioDelay(1);
    }

    // Read 40 bits (5 bytes)
    for (i = 0; i < 40; i++) {
        timeout = 0;
        while (gpioRead(gpio_pin) == 0) {
            timeout++;
            if (timeout > 100) {
                fprintf(stderr, "Error: Timeout waiting for DHT11 data low on GPIO %d\n", gpio_pin);
                data.error = -1; // Indicate error
                return data;
            }
            gpioDelay(1);
        }

        timeout = 0;
        while (gpioRead(gpio_pin) == 1) {
            timeout++;
            if (timeout > 100) {
                fprintf(stderr, "Error: Timeout waiting for DHT11 data high on GPIO %d\n", gpio_pin);
                data.error = -1; // Indicate error
                return data;
            }
            gpioDelay(1);
        }

        if (timeout > 40) {
            dht11_data[i / 8] |= (1 << (7 - (i % 8)));
        }
    }

    // Checksum validation
    if ((dht11_data[0] + dht11_data[1] + dht11_data[2] + dht11_data[3]) & 0xFF != dht11_data[4]) {
        fprintf(stderr, "Error: Checksum failure on GPIO %d\n", gpio_pin);
        data.error = -1; // Indicate error
        return data;
    }

    // Convert data to temperature and humidity
    data.humidity = (float)((dht11_data[0] << 8) | dht11_data[1]) / 10.0;
    data.temperature = (float)(((dht11_data[2] & 0x7F) << 8) | dht11_data[3]) / 10.0;
    if (dht11_data[2] & 0x80) {
        data.temperature = -data.temperature;
    }

    return data;
}

// Function to display the data to the console
void display_data(DHT11Data sensor1, DHT11Data sensor2, DHT11Data sensor3) {
    time_t rawtime;
    struct tm * timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    printf("%s Sensor 1: Temperature = %.1f°C, Humidity = %.1f%%\n", asctime(timeinfo), sensor1.temperature, sensor1.humidity);
    printf("%s Sensor 2: Temperature = %.1f°C, Humidity = %.1f%%\n", asctime(timeinfo), sensor2.temperature, sensor2.humidity);
    printf("%s Sensor 3: Temperature = %.1f°C, Humidity = %.1f%%\n", asctime(timeinfo), sensor3.temperature, sensor3.humidity);

    if (sensor1.error == -1 || sensor2.error == -1 || sensor3.error == -1) {
        fprintf(stderr, "Error: Sensor data is invalid.\n");
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (1) {
        // Read data from sensors
        sensor1_data = read_dht11(DHT11_GPIO_1);
        sensor2_data = read_dht11(DHT11_GPIO_2);
        sensor3_data = read_dht11(DHT11_GPIO_3);

        // Display data
        display_data(sensor1_data, sensor2_data, sensor3_data);

        // Wait for 5 seconds
        gpioDelay(5000000); // 5 seconds in microseconds
    }

    return 0;
}

