// Function to read data from the DHT11 sensor
DHT11Data read_dht11(int gpio) {
    DHT11Data data = {0.0, 0.0, -1}; // Initialize with error status
    int bit_count = 0;
    int byte_index = 0;
    int data_buffer[5] = {0};

    gpioSetMode(gpio, PI_OUTPUT);
    gpioWrite(gpio, 0);
    gpioDelay(1);
    gpioWrite(gpio, 1);
    gpioDelay(30);
    gpioSetMode(gpio, PI_INPUT);

    // Wait for the DHT11 to pull the line low (acknowledge signal)
    int timeout = 0;
    while (gpioRead(gpio) == 1) {
        gpioDelay(1); // Delay 1 microsecond
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 acknowledge signal.\n");
            return data; // Return error status
        }
    }

    timeout = 0;
    while (gpioRead(gpio) == 0) {
        gpioDelay(1);
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 data start signal.\n");
            return data; // Return error status
        }
    }

    timeout = 0;
    while (gpioRead(gpio) == 1) {
        gpioDelay(1);
        timeout++;
        if (timeout > 100) {
            fprintf(stderr, "Error: Timeout waiting for DHT11 data end signal.\n");
            return data; // Return error status
        }
    }

    // Read 40 bits of data
    for (int i = 0; i < 40; i++) {
        timeout = 0;
        while (gpioRead(gpio) == 0) {
            gpioDelay(1);
            timeout++;
            if (timeout > 100) {
                fprintf(stderr, "Error: Timeout waiting for DHT11 bit start.\n");
                return data; // Return error status
            }
        }

        long start = time_time();

        timeout = 0;
        while (gpioRead(gpio) == 1) {
            gpioDelay(1);
            timeout++;
            if (timeout > 100) {
                fprintf(stderr, "Error: Timeout waiting for DHT11 bit end.\n");
                return data; // Return error status
            }
        }

        long end = time_time();
        if (end - start > 40) {
            data_buffer[byte_index] |= (1 << (7 - bit_count));
        }

        bit_count++;
        if (bit_count == 8) {
            byte_index++;
            bit_count = 0;
        }
    }

    // Validate checksum
    if ((data_buffer[0] + data_buffer[1] + data_buffer[2] + data_buffer[3]) != data_buffer[4]) {
