int init_gpio(void) {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi.\n");
        return -1;
    }

    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, LOW); // Initially turn the buzzer off
    printf("GPIO initialized successfully.\n");
    return 0;
}

// Activates the buzzer for 2 seconds
void beep(void) {
    digitalWrite(BUZZER_PIN, HIGH);
    log_message("Buzzer ON");
    delay(2000);
}

// Turns the buzzer off and waits for 3 seconds
void blink_buzzer(void) {
    digitalWrite(BUZZER_PIN, LOW);
    log_message("Buzzer OFF");
    delay(3000);
}

// Logs a timestamped message to the console
void log_message(const char *message) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    printf("[%s] %s\n", timestamp, message);
}

