#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <pigpio.h>
#include <unistd.h>

// Define GPIO pins for LEDs
#define LED_1 16
#define LED_2 20
#define LED_3 21

// Function prototypes
int initialize_gpio();
int blink_led(int gpio_pin);
int handle_blinking(int led_number);
void signal_handler(int signal);

// Global variable to indicate program termination
volatile sig_atomic_t program_running = 1;

int main() {
    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO library
    if (initialize_gpio() != 0) {
        fprintf(stderr, "Failed to initialize GPIO. Exiting.\n");
        return 1;
    }

    // Main loop for blinking sequence
    while (program_running) {
        if (handle_blinking(1) != 0) return 1;
        if (handle_blinking(2) != 0) return 1;
        if (handle_blinking(3) != 0) return 1;
    }

    // Clean up GPIO resources before exiting
    gpioTerminate();
    printf("Program terminated gracefully.\n");
    return 0;
}

// Initializes the pigpio library and sets GPIO pins as outputs
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(LED_1, PI_OUTPUT);
    gpioSetMode(LED_2, PI_OUTPUT);
    gpioSetMode(LED_3, PI_OUTPUT);

    // Ensure all LEDs are off initially
    gpioWrite(LED_1, 0);
    gpioWrite(LED_2, 0);
    gpioWrite(LED_3, 0);

    return 0;
}

// Controls the specified GPIO pin to blink an LED
int blink_led(int gpio_pin) {
    gpioWrite(gpio_pin, 1); // Turn LED on
    usleep(1000000);       // Wait for 1 second
    gpioWrite(gpio_pin, 0); // Turn LED off
    return 0;
    }

// Handles the blinking sequence for a given LED number
int handle_blinking(int led_number) {
    int gpio_pin;

    switch (led_number) {
        case 1:
            gpio_pin = LED_1;
            break;
        case 2:
            gpio_pin = LED_2;
            break;
        case 3:
            gpio_pin = LED_3;
            break;
        default:
            fprintf(stderr, "Invalid LED number: %d\n", led_number);
            return 1;
    }

    printf("LED %d blinking started\n", led_number);
    if (blink_led(gpio_pin) != 0) {
        fprintf(stderr, "Error blinking LED %d\n", led_number);
        return 1;
    }
    printf("LED %d blinking finished\n", led_number);
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C pressed. Exiting...\n");
        program_running = 0;
    }
}

