    unsigned char buffer[3];
    int adc_value = 0;

    buffer[0] = 0x01;                           // Start bit
    buffer[1] = (0x08 | channel) << 4;         // Single-ended mode, channel selection
    buffer[2] = 0x00;                           // Don't care

    digitalWrite(MCP3008_CS_PIN, LOW); // Select the MCP3008
    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3); // Transfer data
    digitalWrite(MCP3008_CS_PIN, HIGH);  // Deselect the MCP3008

    adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];

    return adc_value;
}

// Function to control the LED based on light level
void control_led(int light_level, int threshold) {
    if (light_level < threshold) {
        digitalWrite(LED_PIN, HIGH); // Turn on LED
    } else {
        digitalWrite(LED_PIN, LOW);  // Turn off LED
    }
}

// Function to log data to file
void log_data(int light_level, int led_state) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL) {
        fprintf(log_file, "%s, Light: %d, LED: %s\n", timestamp, light_level, led_state ? "ON" : "OFF");
        fflush(log_file); // Ensure data is written to file immediately
    } else {
        perror("Error writing to log file");
    }
}

int main(void) {
    int light_level, led_state;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "wiringPiSPISetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Set MCP3008 CS pin as output
    pinMode(MCP3008_CS_PIN, OUTPUT);
    digitalWrite(MCP3008_CS_PIN, HIGH); // Deselect MCP3008 initially

    // Set LED pin as output
    pinMode(LED_PIN, OUTPUT);
    digitalWrite(LED_PIN, LOW);          // Initially turn off the LED

    // Open log file
    log_file = fopen("light_data.log", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Light intensity control started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read light level from MCP3008
        light_level = read_mcp3008(0);

        // Control LED
        control_led(light_level, LIGHT_THRESHOLD);
        led_state = digitalRead(LED_PIN);

        // Log data
        log_data(light_level, led_state);

        // Print data to console
        printf("Light Level: %d, LED: %s\n", light_level, led_state ? "ON" : "OFF");

        delay(2000); // Wait 2 seconds
    }

    return 0;
}

