// Function to read temperature from DS18B20 sensor
float readTemperature()
{
    int data[9];
    int i;

    owReset();
    owWriteByte(0xCC); // Skip ROM
    owWriteByte(0x44); // Convert T
    delay(750);         // Wait for conversion

    owReset();
    owWriteByte(0xCC); // Skip ROM
    owWriteByte(0xBE); // Read Scratchpad

    for (i = 0; i < 9; i++)
    {
        data[i] = owReadByte();
    }

    owReset();

    if (data[1] & 0x80) // Check for error bit
    {
        char error_message[100];
        snprintf(error_message, sizeof(error_message), "1-Wire read error: %d", data[1]);
        handleError(error_message);
        return -999.0;
    }

    float temperature = (float)((data[2] << 8) | data[3]) / 16.0;
    return temperature;
}

