    }
}

// 1-Wire communication functions (Simplified, replace with proper library if needed)
int owReadBit()
{
    int bit = 0;
    for (int i = 0; i < 8; i++)
    {
        owPulse();
        delayMicroseconds(1); // Minimum 0.2us
        if (digitalRead(RED_PIN) == LOW)
        {
            bit |= (1 << (7 - i));
        }
        owPulse();
    }
    return bit;
}

void owWriteBit(int bit)
{
    owPulse();
    delayMicroseconds(bit ? 10 : 60); // Minimum 0.2us
    owPulse();
}

void owWriteByte(int byte)
{
    for (int i = 0; i < 8; i++)
    {
        owWriteBit(byte & 1);
        byte >>= 1;
    }
}

int owReadByte()
{
    int byte = 0;
    for (int i = 0; i < 8; i++)
    {
        byte |= (owReadBit() << (7 - i));
    }
    return byte;
}

void owReset()
{
    owPulse();
    delayMicroseconds(480);
    owPulse();
    delayMicroseconds(70);
}

void owPulse()
{
    digitalWrite(RED_PIN, HIGH);
    delayMicroseconds(1);
    digitalWrite(RED_PIN, LOW);
    delayMicroseconds(60);
}

