// Define GPIO pins
#define DS18B20_PIN 21
#define RED_PIN 17
#define GREEN_PIN 18
#define BLUE_PIN 27

// Default temperature thresholds
#define DEFAULT_TEMP_THRESHOLD_HIGH 30.0
#define DEFAULT_TEMP_THRESHOLD_LOW 25.0

// Global variables (to be minimized)
static volatile int keepRunning = 1;
static int i2c_fd;
static FILE *log_file = NULL;

// Structure to hold temperature thresholds
typedef struct {
    float high_temp;
    float low_temp;
} TemperatureThresholds;

// Function prototypes
float readTemperature();
void logTemperature(float temperature);
void logAlert(const char *message);
void setLEDColor(int red, int green, int blue);
void signalHandler(int signum);
int findDS18B20Device(char *device_path);
TemperatureThresholds readThresholds();

// Signal handler for graceful shutdown
void signalHandler(int signum) {
    if (signum == SIGINT) {
        printf("Received SIGINT, shutting down...\n");
        keepRunning = 0;
    }
}

// Reads the temperature from the DS18B20 sensor
float readTemperature() {
    char device_path[256];
    int fd;
    unsigned char scratchpad[9];
    float temperature = -1000.0; // Initialize with an invalid value

    if (findDS18B20Device(device_path) != 0) {
        logAlert("DS18B20 sensor not found.");
        return temperature;
    }

    fd = wiringPiI2CSetup(0); // Use default I2C address
    if (fd == -1) {
        logAlert("Failed to initialize I2C communication.");
        return temperature;
    }

    if (wiringPiI2CWrite(fd, 0xCC) == -1) {
        logAlert("Failed to reset DS18B20.");
        return temperature;
    }
    delay(10); // Wait for reset

    if (wiringPiI2CWrite(fd, 0x44) == -1) {
        logAlert("Failed to convert T.");
        return temperature;
    }
    delay(750); // Wait for conversion

    if (readScratchpad(fd, scratchpad) == -1) {
        logAlert("Failed to read scratchpad.");
        return temperature;
    }

    int16_t rawTemperature = (scratchpad[1] << 8) | scratchpad[0];
    temperature = (float)rawTemperature / 16.0;

    return temperature;
}

// Reads the scratchpad from the DS18B20 sensor
int readScratchpad(int fd, unsigned char *scratchpad) {
    for (int i = 0; i < 9; i++) {
        int data = wiringPiI2CRead(fd);
        if (data == -1) {
            fprintf(stderr, "Error reading scratchpad byte %d: %s\n", i, strerror(errno));
            return -1;
        }
        scratchpad[i] = (unsigned char)data;
    }
    return 0;
}

// Logs the temperature to a file with a timestamp
void logTemperature(float temperature) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s Temperature: %.2f\u00b0C\n", timestamp, temperature);
    fflush(log_file); // Ensure data is written to file immediately
}

// Logs an alert message to a file with a timestamp
void logAlert(const char *message) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s ALERT: %s\n", timestamp, message);
    fflush(log_file);
}

// Sets the color of the RGB LED
void setLEDColor(int red, int green, int blue) {
    pwmWrite(RED_PIN, red);
    pwmWrite(GREEN_PIN, green);
    pwmWrite(BLUE_PIN, blue);
}

// Finds the DS18B20 device directory
int findDS18B20Device(char *device_path) {
    DIR *d;
    struct dirent *dir;

    d = opendir("/sys/bus/w1/devices/");
    if (d) {
        while ((dir = readdir(d)) != NULL) {
            if (strncmp(dir->d_name, "28-", 3) == 0) {
                strcpy(device_path, "/sys/bus/w1/devices/");
                strcat(device_path, dir->d_name);
                closedir(d);
                return 0; // Device found
            }
        }
        closedir(d);
    }
    return -1; // Device not found
}

// Reads temperature thresholds from config file
TemperatureThresholds readThresholds() {
    TemperatureThresholds thresholds;
    thresholds.high_temp = DEFAULT_TEMP_THRESHOLD_HIGH;
    thresholds.low_temp = DEFAULT_TEMP_THRESHOLD_LOW;

    FILE *fp = fopen("temp_config.txt", "r");
    if (fp != NULL) {
        char line[256];
        while (fgets(line, sizeof(line), fp) != NULL) {
            char *key = strtok(line, "=");
            char *value = strtok(NULL, "\n");
            if (key != NULL && value != NULL) {
                if (strcmp(key, "high_temp") == 0) {
                    thresholds.high_temp = atof(value);
                } else if (strcmp(key, "low_temp") == 0) {
                    thresholds.low_temp = atof(value);
                }
            }
        }
        fclose(fp);
    }

    return thresholds;
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Failed to initialize wiringPi.\n");
        return 1;
    }

    // Set GPIO pins to output mode
    pinMode(RED_PIN, PWM_OUTPUT);
    pinMode(GREEN_PIN, PWM_OUTPUT);
    pinMode(BLUE_PIN, PWM_OUTPUT);

    // Initialize PWM
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(255);

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(0);
    if (i2c_fd == -1) {
        fprintf(stderr, "Failed to initialize I2C communication.\n");
        return 1;
    }

    // Open log file
    log_file = fopen("temp_monitor.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file.\n");
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signalHandler);

    // Read temperature thresholds
    TemperatureThresholds thresholds = readThresholds();

    printf("Temperature Monitoring Started. Press Ctrl+C to exit.\n");

    while (keepRunning) {
        float temperature = readTemperature();

        if (temperature > thresholds.high_temp) {
            setLEDColor(255, 0, 0); // Red
            logAlert("Temperature exceeds high threshold.");
        } else if (temperature < thresholds.low_temp) {
            setLEDColor(0, 255, 0); // Green
            logAlert("Temperature exceeds low threshold.");
        } else {
            setLEDColor(0, 0, 255); // Blue
        }

        logTemperature(temperature);
        delay(5000); // Read temperature every 5 seconds
    }

    // Cleanup
    setLEDColor(0, 0, 0); // Turn off LED
    if (log_file != NULL) {
        fclose(log_file);
    }
    close(i2c_fd);

    printf("Temperature Monitoring Stopped.\n");

    return 0;
}

