// Define vibration levels
#define NO_VIBRATION 0
#define LOW_VIBRATION 1
#define MEDIUM_VIBRATION 2
#define HIGH_VIBRATION 3

// Global variables
static volatile int running = 1;
static int log_fd = -1;

// Function prototypes
void vibration_callback(int gpio, int level, uint32_t tick);
int log_vibration_event(int intensity);
void set_led_color(int intensity);
void signal_handler(int signal);

// Vibration callback function
void vibration_callback(int gpio, int level, uint32_t tick) {
    int intensity = NO_VIBRATION;

    if (level == 0) { // Falling edge
        intensity = NO_VIBRATION;
    } else if (level == 1) { // Rising edge
        intensity = HIGH_VIBRATION;
    } else { // Stable state
        intensity = NO_VIBRATION;
    }

    log_vibration_event(intensity);
    set_led_color(intensity);
}

// Function to log vibration events to a file
int log_vibration_event(int intensity) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[64];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    if (log_fd == -1) {
        log_fd = open("vibration_log.txt", O_WRONLY | O_CREAT | O_APPEND, 0644);
        if (log_fd == -1) {
            fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
            return -1;
        }
    }

    FILE *fp = fdopen(log_fd, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening file pointer: %s\n", strerror(errno));
        return -1;
    }

    fprintf(fp, "%s, %d\n", timestamp, intensity);
    fflush(fp);

    fclose(fp);
    return 0;
}

// Function to set the color of the LED based on vibration intensity
void set_led_color(int intensity) {
    switch (intensity) {
        case NO_VIBRATION:
            gpioWrite(LED_RED_PIN, 0);
            gpioWrite(LED_GREEN_PIN, 0);
            break;
        case LOW_VIBRATION:
            gpioWrite(LED_RED_PIN, 1);
            gpioWrite(LED_GREEN_PIN, 0);
            break;
        case MEDIUM_VIBRATION:
            gpioWrite(LED_RED_PIN, 0);
            gpioWrite(LED_GREEN_PIN, 1);
            break;
        case HIGH_VIBRATION:
            gpioWrite(LED_RED_PIN, 1);
            gpioWrite(LED_GREEN_PIN, 1);
            break;
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
    gpioTerminate();
    if (log_fd != -1) {
        close(log_fd);
    }
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", strerror(errno));
        return 1;
    }

    // Set GPIO pins as input/output
    gpioSetMode(VIBRATION_PIN, PI_INPUT);
    gpioSetMode(LED_RED_PIN, PI_OUTPUT);
    gpioSetMode(LED_GREEN_PIN, PI_OUTPUT);

    // Set pull-up/down resistor (optional, adjust as needed)
    gpioSetPullUpDown(VIBRATION_PIN, PI_PUD_UP);

    // Set up interrupt handler for falling edge detection
    if (gpioSetAlertFuncEx(VIBRATION_PIN, vibration_callback, NULL) != 0) {
        fprintf(stderr, "Failed to set alert function: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Vibration detection started. Press Ctrl+C to exit.\n");

    // Main loop (keep the program running until a signal is received)
    while (running) {
        gpioDelay(100); // Sleep for 100ms to reduce CPU usage
    }

    // Clean up (should not reach here if signal handler works correctly)
    gpioTerminate();
    if (log_fd != -1) {
        close(log_fd);
    }

    return 0;
}

